import { cleanImageUrl } from '../utils';

interface FlashcardsProps {
  data: Question[];
  onImageClick?: (url: string) => void;
  mistakes?: string[]; 
  onToggleMistake?: (id: string, shouldAdd: boolean) => void; 
  onClearMistakes?: () => void;
}

export const Flashcards: React.FC<FlashcardsProps> = ({ 
    data, 
    onImageClick, 
    mistakes = [], 
    onToggleMistake, 
    onClearMistakes 
}) => {
  const [currentIndex, setCurrentIndex] = useState(() => {
    const saved = localStorage.getItem('ot_flashcard_index');
    return saved ? parseInt(saved, 10) : 0;
  });

  const [isShuffled, setIsShuffled] = useState(() => {
    return localStorage.getItem('ot_flashcard_shuffle') === 'true';
  });

  const [isReversed, setIsReversed] = useState(() => {
    return localStorage.getItem('ot_flashcard_reversed') === 'true';
  });

  const [isFlipped, setIsFlipped] = useState(false);

  const [showImagesOnly, setShowImagesOnly] = useState(() => localStorage.getItem('ot_filter_images') === 'true');
  const [showMistakesOnly, setShowMistakesOnly] = useState(() => localStorage.getItem('ot_filter_mistakes') === 'true');
  const [selectedCategories, setSelectedCategories] = useState<string[]>(() => {
    try {
      return JSON.parse(localStorage.getItem('ot_filter_categories') || '[]');
    } catch { return []; }
  });

  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const { speak, cancel, isSpeaking, speakingId } = useSpeech();

  const [touchStart, setTouchStart] = useState<{ x: number; y: number } | null>(null);
  const [touchEnd, setTouchEnd] = useState<{ x: number; y: number } | null>(null);
  const minSwipeDistance = 50;

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category));
    return Array.from(cats).sort((a: string, b: string) => 
      a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' })
    );
  }, [data]);

  const activeData = useMemo(() => {
    let filtered = data;
    if (showMistakesOnly) filtered = filtered.filter(q => mistakes.includes(q.id));
    if (showImagesOnly) filtered = filtered.filter(q => q.questionImage || q.answerImage);
    if (selectedCategories.length > 0) filtered = filtered.filter(q => selectedCategories.includes(q.category));

    if (isShuffled) {
        return [...filtered].sort((a, b) => a.id.localeCompare(b.id)); // Consistent sort for now
    }
    return filtered;
  }, [data, showImagesOnly, selectedCategories, showMistakesOnly, mistakes, isShuffled]);

  useEffect(() => localStorage.setItem('ot_flashcard_index', currentIndex.toString()), [currentIndex]);
  useEffect(() => localStorage.setItem('ot_flashcard_shuffle', String(isShuffled)), [isShuffled]);
  useEffect(() => localStorage.setItem('ot_flashcard_reversed', String(isReversed)), [isReversed]);
  useEffect(() => localStorage.setItem('ot_filter_images', String(showImagesOnly)), [showImagesOnly]);
  useEffect(() => localStorage.setItem('ot_filter_mistakes', String(showMistakesOnly)), [showMistakesOnly]);
  useEffect(() => localStorage.setItem('ot_filter_categories', JSON.stringify(selectedCategories)), [selectedCategories]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (isFilterOpen) return;
      if (e.key === 'ArrowRight') {
        if (currentIndex < activeData.length - 1) {
          setIsFlipped(false);
          cancel();
          setTimeout(() => setCurrentIndex(c => c + 1), 150);
        }
      } else if (e.key === 'ArrowLeft') {
        if (currentIndex > 0) {
          setIsFlipped(false);
          cancel();
          setTimeout(() => setCurrentIndex(c => c - 1), 150);
        }
      } else if (e.key === ' ' || e.key === 'Enter') {
        e.preventDefault();
        setIsFlipped(prev => !prev);
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [currentIndex, activeData.length, isFilterOpen, cancel]); 

  const handleResolveMistake = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    onToggleMistake?.(id, false);
  };

  const handleWipeVault = () => {
    if (confirm("Permanently delete all recorded mistakes?")) {
        onClearMistakes?.();
        setShowMistakesOnly(false);
    }
  };

  useEffect(() => {
    if (activeData.length > 0 && currentIndex >= activeData.length) {
      setCurrentIndex(0);
    }
  }, [activeData.length]);

  const currentCard = activeData[currentIndex];

  const frontContent = isReversed ? {
    label: 'Answer', text: currentCard?.answerText, image: currentCard?.answerImage, isQuestion: false
  } : {
    label: 'Question', text: currentCard?.questionText, image: currentCard?.questionImage, isQuestion: true
  };

  const backContent = isReversed ? {
    label: 'Question', text: currentCard?.questionText, image: currentCard?.questionImage, isQuestion: true
  } : {
    label: 'Answer', text: currentCard?.answerText, image: currentCard?.answerImage, isQuestion: false
  };

  const handleNext = (e?: React.MouseEvent) => {
    e?.stopPropagation();
    if (currentIndex < activeData.length - 1) {
      setIsFlipped(false);
      cancel();
      setTimeout(() => setCurrentIndex(c => c + 1), 150);
    }
  };

  const handlePrev = (e?: React.MouseEvent) => {
    e?.stopPropagation();
    if (currentIndex > 0) {
      setIsFlipped(false);
      cancel();
      setTimeout(() => setCurrentIndex(c => c - 1), 150);
    }
  };

  const onTouchStart = (e: React.TouchEvent) => {
    setTouchEnd(null);
    setTouchStart({ x: e.targetTouches[0].clientX, y: e.targetTouches[0].clientY });
  };

  const onTouchMove = (e: React.TouchEvent) => {
    setTouchEnd({ x: e.targetTouches[0].clientX, y: e.targetTouches[0].clientY });
  };

  const onTouchEnd = () => {
    if (!touchStart || !touchEnd) return;
    const distanceX = touchStart.x - touchEnd.x;
    const distanceY = touchStart.y - touchEnd.y;
    if (Math.abs(distanceX) > Math.abs(distanceY)) {
      if (distanceX > minSwipeDistance) handleNext();
      else if (distanceX < -minSwipeDistance) handlePrev();
    }
  };

  const handleSpeak = (e: React.MouseEvent, text: string, suffix: string) => {
    e.stopPropagation();
    if (isSpeaking) cancel(); else speak(text, currentCard.id + suffix);
  };

  const getTextSizeClass = (text: string = '') => {
    const len = text.length;
    if (len < 20) return 'text-3xl md:text-5xl';
    if (len < 60) return 'text-2xl md:text-4xl';
    if (len < 120) return 'text-xl md:text-3xl';
    if (len < 250) return 'text-lg md:text-2xl';
    if (len < 400) return 'text-base md:text-xl';
    return 'text-sm md:text-lg'; 
  };

  const formatCardText = (text: string = '') => {
    if (!text) return '';
    return text
      .replace(/^Define the term:\s*/i, '')
      .replace(/^Anatomical term for:\s*/i, '')
      .replace(/^Define:\s*/i, '')
      .replace(/^Identify the\s+/i, '')
      .trim();
  };

  const filterOptions: FilterOption[] = [
    {
        label: 'Diagrams Only',
        subLabel: 'Visual Study',
        icon: ImageIcon,
        isActive: showImagesOnly,
        onClick: () => { setShowImagesOnly(!showImagesOnly); setShowMistakesOnly(false); },
        colorTheme: 'indigo'
    }
  ];

  if (!currentCard) {
    return (
      <div className="flex flex-col items-center justify-center h-full p-8 text-center space-y-8 animate-in fade-in zoom-in-95 duration-500">
        <div className={`w-24 h-24 rounded-full flex items-center justify-center shadow-lg border-4 ${showMistakesOnly ? 'bg-rose-50 text-rose-600 border-rose-100' : 'bg-white text-slate-400 border-slate-100'}`}>
           {showMistakesOnly ? <Trophy size={48} /> : <Layers size={48} />}
        </div>
        <div className="space-y-3 max-w-xs mx-auto">
            <h3 className="text-2xl font-bold text-slate-900 tracking-tight font-display">
                {showMistakesOnly ? "Review Complete" : "No Cards Found"}
            </h3>
            <p className="text-slate-500 font-medium leading-relaxed">
                {showMistakesOnly ? "Excellent work! You've resolved all items in your Smart Review list." : "Try adjusting your filters to see more cards."}
            </p>
        </div>
        <button 
          onClick={() => { setSelectedCategories([]); setShowImagesOnly(false); setShowMistakesOnly(false); }}
          className="px-8 py-3 bg-slate-900 text-white rounded-xl font-bold uppercase tracking-widest text-xs hover:bg-slate-800 transition-all shadow-lg active:scale-95"
        >
          Reset Filters
        </button>
      </div>
    );
  }

  const frontDisplayText = formatCardText(frontContent.text);
  const backDisplayText = formatCardText(backContent.text);

  return (
    <div className="flex flex-col h-full max-w-5xl mx-auto w-full relative">
      {/* Top Controls */}
      <div className="flex justify-between items-center px-4 md:px-6 py-2 md:py-6 shrink-0 gap-3 overflow-x-auto no-scrollbar">
        <div className="flex items-center gap-2">
           <button 
             onClick={() => setIsFilterOpen(true)}
             className={`w-10 h-10 md:w-12 md:h-12 rounded-2xl border transition-all flex items-center justify-center shrink-0 ${selectedCategories.length > 0 || showImagesOnly ? 'border-rose-200 bg-rose-50 text-rose-700' : 'bg-white border-slate-200 text-slate-400 hover:border-slate-300'}`}
           >
             <Filter className="w-4 h-4 md:w-[18px] md:h-[18px]" strokeWidth={2} />
           </button>

           {mistakes.length > 0 && (
                <button 
                    onClick={() => { setShowMistakesOnly(!showMistakesOnly); if(!showMistakesOnly) setCurrentIndex(0); }}
                    className={`flex items-center gap-2 px-3 py-1 md:py-2 md:px-4 rounded-xl border transition-all shrink-0 ${showMistakesOnly ? 'bg-rose-100 border-rose-300 text-rose-800 shadow-sm' : 'bg-white border-slate-200 text-slate-500 hover:border-rose-200 hover:text-rose-600'}`}
                >
                    <AlertTriangle size={16} className={showMistakesOnly ? "fill-rose-500 text-rose-600" : ""} />
                    <div className="flex flex-col items-start text-[10px] uppercase font-black tracking-wider leading-none">
                        <span>Smart Review</span>
                        <span className="opacity-60 text-[9px] mt-0.5">{mistakes.length} Items</span>
                    </div>
                </button>
           )}
        </div>

        <div className="flex items-center gap-2">
           <span className="text-base md:text-lg font-black text-slate-900 font-display flex items-baseline gap-1 mr-2 hidden sm:flex">
                 {currentIndex + 1} 
                 <span className="text-xs md:text-sm font-bold text-slate-300">/ {activeData.length}</span>
           </span>

           <button 
             onClick={() => { setIsReversed(!isReversed); setIsFlipped(false); }}
             className={`w-10 h-10 md:w-12 md:h-12 rounded-2xl border transition-all flex items-center justify-center hover:bg-slate-50 shrink-0 ${isReversed ? 'border-emerald-500 text-emerald-600 bg-emerald-50' : 'bg-white border-slate-200 text-slate-400'}`}
             title="Reverse Sides"
           >
             <ArrowLeftRight className="w-4 h-4 md:w-[18px] md:h-[18px]" strokeWidth={2} />
           </button>
           <button 
             onClick={() => { setIsShuffled(!isShuffled); setCurrentIndex(0); }}
             className={`w-10 h-10 md:w-12 md:h-12 rounded-2xl border transition-all flex items-center justify-center hover:bg-slate-50 shrink-0 ${isShuffled ? 'border-purple-500 text-purple-600 bg-purple-50' : 'bg-white border-slate-200 text-slate-400'}`}
             title="Shuffle Deck"
           >
             <Shuffle className="w-4 h-4 md:w-[18px] md:h-[18px]" strokeWidth={2} />
           </button>
        </div>
      </div>

      {/* Card Container */}
      <div className="flex-1 px-4 md:px-8 pb-2 flex flex-col justify-center min-h-0 relative perspective-1000">
        <div 
          className="relative w-full h-full cursor-pointer select-none"
          onClick={() => setIsFlipped(!isFlipped)}
          onTouchStart={onTouchStart}
          onTouchMove={onTouchMove}
          onTouchEnd={onTouchEnd}
        >
          <div className={`relative w-full h-full transition-all duration-500 transform-style-3d ${isFlipped ? 'rotate-y-180' : ''}`}>

            {/* FRONT FACE */}
            <div className="absolute inset-0 backface-hidden bg-white rounded-[2rem] md:rounded-[2.5rem] shadow-card hover:shadow-card-hover border border-slate-100 p-5 md:p-12 flex flex-col group overflow-hidden">
               <div className="w-full flex justify-between items-start mb-2 shrink-0">
                   <span className="text-[9px] md:text-[10px] font-black uppercase tracking-[0.3em] text-slate-300">
                     {frontContent.label}
                   </span>
               </div>

               <div className="flex-1 w-full overflow-y-auto custom-scrollbar relative">
                 <div className="min-h-full flex flex-col items-center justify-center py-2 space-y-4 md:space-y-6">
                    {frontContent.image && (
                      <div 
                        className="w-full flex items-center justify-center rounded-xl md:rounded-2xl p-2 md:p-4 bg-slate-50/50 border border-slate-100 relative group/img cursor-zoom-in shrink-0"
                        onClick={(e) => { e.stopPropagation(); onImageClick?.(frontContent.image!); }}
                      >
                        <img 
                          src={cleanImageUrl(frontContent.image)} 
                          className="max-h-[30vh] md:max-h-[40vh] max-w-full object-contain rounded-lg" 
                          alt="Content" 
                        />
                        <div className="absolute top-2 right-2 p-2 bg-black/50 text-white rounded-lg opacity-0 group-hover/img:opacity-100 transition-opacity">
                            <Search size={14} />
                        </div>
                      </div>
                    )}

                    <h2 
                        className={`font-bold leading-tight text-slate-800 break-words w-full text-center font-display ${getTextSizeClass(frontDisplayText)}`} 
                        dangerouslySetInnerHTML={{ __html: frontDisplayText }} 
                    />
                 </div>
               </div>

                <button 
                    onClick={(e) => handleSpeak(e, frontDisplayText, '-front')}
                    className="absolute bottom-6 right-6 md:bottom-8 md:right-8 w-10 h-10 md:w-12 md:h-12 flex items-center justify-center bg-slate-900 text-white rounded-full hover:bg-rose-600 shadow-xl shadow-slate-200 hover:shadow-rose-200 transition-all z-20 hover:scale-110 active:scale-95"
                >
                    {isSpeaking && speakingId?.endsWith('-front') ? (
                        <div className="flex gap-0.5 items-center justify-center h-3">
                            <div className="w-0.5 h-full bg-white rounded-full animate-[pulse_0.6s_ease-in-out_infinite]"></div>
                            <div className="w-0.5 h-3/4 bg-white rounded-full animate-[pulse_0.6s_ease-in-out_0.2s_infinite]"></div>
                            <div className="w-0.5 h-1/2 bg-white rounded-full animate-[pulse_0.6s_ease-in-out_0.4s_infinite]"></div>
                        </div>
                    ) : (
                        <Volume2 className="w-[18px] h-[18px] md:w-5 md:h-5" />
                    )}
                </button>
            </div>

            {/* BACK FACE - Revised for Better Explanation Layout */}
            <div className="absolute inset-0 backface-hidden rotate-y-180 bg-slate-900 rounded-[2rem] md:rounded-[2.5rem] shadow-premium border border-slate-800 p-5 md:p-12 flex flex-col group overflow-hidden">
               <div className="w-full flex justify-between items-start mb-2 shrink-0">
                   <span className="text-[9px] md:text-[10px] font-black uppercase tracking-[0.3em] text-slate-500">
                     {backContent.label}
                   </span>
                   {mistakes.includes(currentCard.id) && (
                        <button 
                            onClick={(e) => handleResolveMistake(currentCard.id, e)}
                            className="flex items-center gap-1.5 px-3 py-1.5 bg-rose-500/20 text-rose-400 rounded-lg text-[10px] font-black uppercase tracking-widest hover:bg-emerald-500/20 hover:text-emerald-400 transition-colors border border-rose-500/30 shadow-lg"
                        >
                            <CheckCircle2 size={12} /> Mastered
                        </button>
                   )}
               </div>

               <div className="flex-1 w-full overflow-y-auto custom-scrollbar relative flex flex-col">
                 <div className="flex-1 flex flex-col items-center justify-center py-4 space-y-6">
                    {backContent.image && (
                      <div 
                        className="w-full flex items-center justify-center rounded-xl md:rounded-2xl p-2 md:p-4 bg-white/5 border border-white/10 relative group/img cursor-zoom-in shrink-0"
                        onClick={(e) => { e.stopPropagation(); onImageClick?.(backContent.image!); }}
                      >
                        <img 
                          src={cleanImageUrl(backContent.image)} 
                          className="max-h-[25vh] md:max-h-[35vh] max-w-full object-contain rounded-lg" 
                          alt="Content" 
                        />
                        <div className="absolute top-2 right-2 p-2 bg-black/50 text-white rounded-lg opacity-0 group-hover/img:opacity-100 transition-opacity">
                            <Search size={14} />
                        </div>
                      </div>
                    )}

                    <p 
                        className={`font-bold leading-relaxed text-emerald-400 break-words w-full text-center font-display ${getTextSizeClass(backDisplayText)}`} 
                        dangerouslySetInnerHTML={{ __html: backDisplayText }} 
                    />
                 </div>

                 {/* Improved Explanation Section - Legendary Style */}
                 {!backContent.isQuestion && currentCard.explanation && (
                    <div className="mt-6 shrink-0 animate-in slide-in-from-bottom-4 duration-500 border-t border-slate-800 pt-4">
                        <div className="flex items-center gap-2 mb-3 text-rose-400">
                            <Sparkles className="w-4 h-4" />
                            <span className="text-[10px] font-black uppercase tracking-[0.2em]">Comprehensive Analysis</span>
                        </div>
                        <div className="bg-slate-800/50 backdrop-blur-sm rounded-2xl p-5 border border-slate-700/50 shadow-inner">
                            <p 
                                className="text-base md:text-lg font-medium text-slate-200 leading-relaxed font-sans" 
                                dangerouslySetInnerHTML={{ __html: currentCard.explanation }} 
                            />
                        </div>
                    </div>
                 )}
               </div>

                <button 
                    onClick={(e) => handleSpeak(e, backDisplayText, '-back')}
                    className="absolute bottom-6 right-6 md:bottom-8 md:right-8 w-10 h-10 md:w-12 md:h-12 flex items-center justify-center bg-white text-slate-900 rounded-full hover:bg-emerald-400 hover:text-white shadow-xl shadow-black/20 transition-all z-20 hover:scale-110 active:scale-95"
                >
                    {isSpeaking && speakingId?.endsWith('-back') ? (
                        <div className="flex gap-0.5 items-center justify-center h-3">
                            <div className="w-0.5 h-full bg-current rounded-full animate-[pulse_0.6s_ease-in-out_infinite]"></div>
                            <div className="w-0.5 h-3/4 bg-current rounded-full animate-[pulse_0.6s_ease-in-out_0.2s_infinite]"></div>
                            <div className="w-0.5 h-1/2 bg-current rounded-full animate-[pulse_0.6s_ease-in-out_0.4s_infinite]"></div>
                        </div>
                    ) : (
                        <Volume2 className="w-[18px] h-[18px] md:w-5 md:h-5" />
                    )}
                </button>
            </div>
          </div>
        </div>
      )}

      {/* Navigation - Bottom */}
      <div className="px-6 pb-6 pt-2 flex justify-center gap-4 md:gap-6 items-center shrink-0">
        <button onClick={handlePrev} disabled={currentIndex === 0} className="w-12 h-12 md:w-14 md:h-14 rounded-2xl bg-white border border-slate-200 flex items-center justify-center text-slate-400 disabled:opacity-40 shadow-sm active:translate-y-0.5">
          <ArrowLeft className="w-5 h-5 md:w-6 md:h-6" />
        </button>

        <button onClick={() => setIsFlipped(!isFlipped)} className="h-12 md:h-14 px-8 md:px-12 rounded-2xl bg-rose-600 flex items-center gap-3 text-white transition-all shadow-lg font-black uppercase text-[10px] md:text-xs tracking-[0.2em] group">
            <RotateCcw className={`w-4 h-4 md:w-[18px] md:h-[18px] transition-transform duration-500 ${isFlipped ? '-rotate-180' : 'rotate-0'}`} />
            Flip Card
        </button>

        <button onClick={handleNext} disabled={currentIndex === activeData.length - 1} className="w-12 h-12 md:w-14 md:h-14 rounded-2xl bg-white border border-slate-200 flex items-center justify-center text-slate-400 disabled:opacity-40 shadow-sm active:translate-y-0.5">
          <ArrowRight className="w-5 h-5 md:w-6 md:h-6" />
        </button>
      </div>

      <FilterModal
        isOpen={isFilterOpen}
        onClose={() => setIsFilterOpen(false)}
        categories={categories}
        selectedCategories={selectedCategories}
        onToggleCategory={(cat) => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])}
        onClearAll={() => { setSelectedCategories([]); setShowImagesOnly(false); setShowMistakesOnly(false); }}
        onWipeVault={mistakes.length > 0 ? handleWipeVault : undefined}
        mainOptions={filterOptions}
        title="Deck Filters"
      />
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import Header from './components/Header';
import { Flashcards } from './components/Flashcards';
import Quiz from './components/Quiz';
import QuestionList from './components/QuestionList';
import InteractiveAtlas from './components/InteractiveAtlas';
import MobileNavigation from './components/MobileNavigation';
import ImageZoomModal from './components/ImageZoomModal';
import { AppMode, Question } from './types';

// Import all available chapters
import { questions as ch1 } from './hooks/data_ch1';
import { questions as ch2 } from './hooks/data_ch2';
import { questions as ch3 } from './hooks/data_ch3';
import { questions as ch4 } from './hooks/data_ch4';
import { questions as ch5 } from './hooks/data_ch5';
import { questions as ch6 } from './hooks/data_ch6';
import { questions as ch7 } from './hooks/data_ch7';
import { questions as ch8 } from './hooks/data_ch8';
import { questions as ch9 } from './hooks/data_ch9';
import { questions as ch10 } from './hooks/data_ch10';
import { questions as ch11 } from './hooks/data_ch11';
import { questions as ch12 } from './hooks/data_ch12';
import { questions as ch13 } from './hooks/data_ch13';
import { questions as ch14 } from './hooks/data_ch14';
import { questions as ch15 } from './hooks/data_ch15';
import { questions as ch16 } from './hooks/data_ch16';
import { questions as ch17 } from './hooks/data_ch17';
import { questions as boostQuestions } from './hooks/data_utilization_boost';

import { Trash2, BookOpen, Stethoscope, HeartPulse, ChevronRight } from 'lucide-react';

const App: React.FC = () => {
  const [hasStarted, setHasStarted] = useState(() => {
    return localStorage.getItem('ot_has_started') === 'true';
  });

  const [currentMode, setCurrentMode] = useState<AppMode>(() => {
    const savedMode = localStorage.getItem('ot_current_mode');
    if (!Object.values(AppMode).includes(savedMode as AppMode)) {
        return AppMode.FLASHCARDS;
    }
    return (savedMode as AppMode) || AppMode.FLASHCARDS;
  });

  const [isHeaderVisible, setIsHeaderVisible] = useState(true);
  const [zoomedImage, setZoomedImage] = useState<string | null>(null);

  const [userVault, setUserVault] = useState<Question[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_ultimate_vault_v5');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_mistakes_v5');
      return saved ? JSON.parse(saved) : [];
    } catch { return []; }
  });

  useEffect(() => {
    localStorage.setItem('ot_current_mode', currentMode);
  }, [currentMode]);

  useEffect(() => {
    localStorage.setItem('ot_has_started', String(hasStarted));
  }, [hasStarted]);

  useEffect(() => {
    localStorage.setItem('anatomy_ultimate_vault_v5', JSON.stringify(userVault));
  }, [userVault]);

  useEffect(() => {
    localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault));
  }, [mistakesVault]);

  useEffect(() => {
    setIsHeaderVisible(true);
  }, [currentMode]);

  const handleToggleMistake = (id: string, shouldAdd: boolean) => {
    setMistakesVault(prev => {
        if (shouldAdd) {
            return prev.includes(id) ? prev : [...prev, id];
        } else {
            return prev.filter(m => m !== id);
        }
    });
  };

  const handleClearMistakes = () => {
      setMistakesVault([]);
  };

  // --- ULTIMATE 2.0 DATA ENGINE (High Utilization & Smart Rationale) ---
  const allQuestions = useMemo(() => {
    const uniqueQuestions: Question[] = [];
    const seenIds = new Set<string>();

    const rawSources = [
        ...ch1, ...ch2, ...ch3, ...ch4, ...ch5, ...ch6, 
        ...ch7, ...ch8, ...ch9, ...ch10, ...ch11, ...ch12, ...ch13, ...ch14, ...ch15, ...ch16, ...ch17,
        ...boostQuestions, ...userVault
    ];

    const clean = (str: string | undefined) => str ? str.trim().replace(/\s+/g, ' ') : '';
    const categoryAnswerPools: Record<string, string[]> = {};

    // First pass: Build highly specific pools for distractors
    rawSources.forEach(q => {
        const cat = q.category || 'General';
        if (!categoryAnswerPools[cat]) categoryAnswerPools[cat] = [];
        const ans = clean(q.answerText);
        if (ans && ans.length < 80) categoryAnswerPools[cat].push(ans);
    });

    // Second pass: Process questions and generate SMART options & RATIONALES
    rawSources.forEach(q => {
        if (!seenIds.has(q.id)) {
            let explanation = clean(q.explanation);
            const answer = clean(q.answerText);
            const question = clean(q.questionText);

            // --- SMART RATIONALE GENERATOR ---
            // If explanation is missing, generate a structured, context-aware rationale
            if (!explanation) {
                const qTextLower = question.toLowerCase();
                const topic = q.category.includes(':') ? q.category.split(':')[1].trim() : q.category;

                if (question.startsWith("Define") || qTextLower.includes("definition") || qTextLower.includes("what is")) {
                     explanation = `<strong>Definition:</strong> <strong>${answer}</strong> is the precise scientific definition. Mastery of this terminology is essential for accurate communication in the context of ${topic}.`;
                }
                else if (question.startsWith("Anatomical term")) {
                     const target = question.split(':')[1]?.trim() || 'the indicated region';
                     explanation = `<strong>Anatomical Terminology:</strong> The standard medical term for "${target}" is <strong>${answer}</strong>. Using specific directional and regional terminology eliminates ambiguity in clinical practice.`;
                }
                else if (qTextLower.includes("identify") || qTextLower.includes("diagram") || qTextLower.includes("shown") || qTextLower.includes("labeled")) {
                    explanation = `<strong>Anatomical Identification:</strong> The structure indicated is the <strong>${answer}</strong>. Identification is based on its unique morphology and spatial relationship to adjacent landmarks within the ${topic}.`;
                } 
                else if (qTextLower.includes("function") || qTextLower.includes("action") || qTextLower.includes("role") || qTextLower.includes("physiology") || qTextLower.includes("do?")) {
                    explanation = `<strong>Physiological Mechanism:</strong> The primary function of <strong>${answer}</strong> is described here. This mechanism is integral to the homeostatic operation of ${topic}.`;
                }
                else if (qTextLower.includes("located") || qTextLower.includes("found") || qTextLower.includes("where")) {
                    explanation = `<strong>Spatial Anatomy:</strong> <strong>${answer}</strong> is situated in this specific region. Knowledge of anatomical planes and relationships is critical for surgical and diagnostic localization.`;
                } 
                else if (qTextLower.includes("composed of") || qTextLower.includes("made of") || qTextLower.includes("type of tissue")) {
                    explanation = `<strong>Histological Structure:</strong> <strong>${answer}</strong> is the correct tissue or chemical classification. The structural composition directly dictates the functional capabilities of this component.`;
                }
                else if (qTextLower.includes("order") || qTextLower.includes("sequence") || qTextLower.includes("pathway")) {
                    explanation = `<strong>Sequential Process:</strong> The correct order is <strong>${answer}</strong>. Physiological processes often rely on a specific cascade of events to function correctly.`;
                }
                else if (qTextLower.includes("nerve") || qTextLower.includes("neuron") || qTextLower.includes("potential") || qTextLower.includes("signal") || qTextLower.includes("synapse")) {
                    explanation = `<strong>Neural Mechanism:</strong> The correct answer is <strong>${answer}</strong>. This involves the generation, transmission, or integration of electrical signals essential for nervous system communication.`;
                }
                else {
                    explanation = `<strong>Core Concept:</strong> The correct answer is <strong>${answer}</strong>. This choice best fits the criteria described, distinguishing it from the distractors based on fundamental principles of ${topic}.`;
                }
            }

            const cleanQ: Question = {
                ...q,
                questionText: question,
                answerText: answer,
                explanation: explanation, // Enriched Explanation
                options: (q.options || []).map(clean).filter(Boolean)
            };

            // DATA INTEGRITY CHECK: Ensure Answer is in Options
            if (cleanQ.options.length > 0) {
               // Case-insensitive check
               const matchIndex = cleanQ.options.findIndex(o => o.toLowerCase() === cleanQ.answerText.toLowerCase());

               if (matchIndex === -1) {
                   // Answer is missing from options. Add it.
                   if (cleanQ.options.length >= 4) {
                       const replaceIdx = Math.floor(Math.random() * cleanQ.options.length);
                       cleanQ.options[replaceIdx] = cleanQ.answerText;
                   } else {
                       cleanQ.options.push(cleanQ.answerText);
                   }
                   // Re-shuffle to hide the insertion
                   cleanQ.options.sort(() => 0.5 - Math.random());
               } else {
                   // Ensure exact string match for strict equality checks
                   cleanQ.options[matchIndex] = cleanQ.answerText;
               }
            }

            const cat = q.category || 'General';
            const pool = categoryAnswerPools[cat] || [];

            // If the question lacks options, generate 3 extremely relevant distractors
            if (cleanQ.options.length < 2) {
                const sameCatDistractors = pool
                    .filter(a => a.toLowerCase() !== cleanQ.answerText.toLowerCase())
                    .sort(() => 0.5 - Math.random())
                    .slice(0, 3);

                cleanQ.options = [cleanQ.answerText, ...sameCatDistractors].sort(() => 0.5 - Math.random());
            }

            uniqueQuestions.push(cleanQ);
            seenIds.add(cleanQ.id);
        }
    });

    return uniqueQuestions;
  }, [userVault]);

  if (!hasStarted) {
    return (
      <div className="h-[100dvh] w-full bg-slate-950 flex flex-col items-center justify-center p-4 md:p-6 relative overflow-hidden font-sans text-white">
         <div className="absolute inset-0 bg-slate-900"></div>
         <div className="absolute top-0 left-0 right-0 h-[40vh] bg-rose-600 rounded-b-[3rem] md:rounded-b-[4rem] z-0 blur-3xl opacity-20"></div>

         <div className="relative z-10 w-full max-w-md mx-auto flex flex-col items-center text-center space-y-10 md:space-y-12 animate-fade-in">
            <div className="w-24 h-24 md:w-28 md:h-28 bg-white rounded-[2rem] shadow-2xl flex items-center justify-center relative cursor-pointer hover:scale-110 transition-transform duration-500" onClick={() => setHasStarted(true)}>
                <HeartPulse size={48} className="text-rose-600 md:w-14 md:h-14" strokeWidth={1.5} />
            </div>

            <div className="space-y-4">
               <span className="inline-block px-4 py-1.5 md:px-5 md:py-2 rounded-full bg-rose-500/10 text-rose-500 text-[10px] md:text-xs font-black uppercase tracking-[0.3em] border border-rose-500/20 shadow-glow">
                  Advanced OT Registry
               </span>
               <h1 className="text-3xl md:text-5xl font-black text-white tracking-tighter leading-tight font-display">
                  Anatomy and <br/><span className="text-rose-600">Physiology</span> OT
               </h1>
            </div>

            <div className="w-full space-y-6">
                <button 
                  onClick={() => setHasStarted(true)}
                  className="w-full py-5 md:py-6 bg-white text-slate-950 rounded-[2rem] font-black uppercase tracking-widest text-xs shadow-[0_20px_50px_rgba(225,29,72,0.3)] hover:bg-rose-600 hover:text-white transition-all transform active:scale-95 flex items-center justify-center gap-4"
                >
                     <span>Access Curriculum</span>
                     <ChevronRight size={20} />
                </button>

                <div className="flex justify-center items-center gap-8 md:gap-10 text-slate-500">
                    <div className="flex flex-col items-center gap-2">
                        <BookOpen size={20} className="text-rose-600/50 md:w-6 md:h-6" />
                        <span className="text-[10px] md:text-[11px] font-black uppercase tracking-widest text-slate-300">{allQuestions.length} Questions</span>
                    </div>
                    <div className="w-px h-8 md:h-10 bg-slate-800"></div>
                    <div className="flex flex-col items-center gap-2">
                        <Stethoscope size={20} className="text-rose-600/50 md:w-6 md:h-6" />
                        <span className="text-[10px] md:text-[11px] font-black uppercase tracking-widest text-slate-300">Boards v7.0</span>
                    </div>
                </div>
            </div>
         </div>
      </div>
    );
  }

  return (
    <div className="h-[100dvh] w-full flex flex-col font-sans text-slate-900 overflow-hidden bg-slate-50/50">
      {isHeaderVisible && (
        <Header 
            currentMode={currentMode} 
            onModeChange={(m) => setCurrentMode(m)} 
            mistakesCount={mistakesVault.length}
        />
      )}

      <main className={`flex-1 relative overflow-hidden flex flex-col w-full mx-auto transition-all duration-700 ease-[cubic-bezier(0.16,1,0.3,1)] ${isHeaderVisible ? 'pt-0 md:pt-4 md:pb-6 max-w-[1400px] px-0 md:px-6' : 'max-w-full'}`}>
        <div className={`w-full h-full md:rounded-[2.5rem] overflow-hidden shadow-none md:shadow-2xl md:border border-white/80 bg-white md:bg-white/80 backdrop-blur-3xl relative z-10 transition-all duration-700 flex flex-col ${!isHeaderVisible ? 'rounded-none border-none bg-white' : ''}`}>

            {currentMode === AppMode.FLASHCARDS && (
              <div className="w-full h-full animate-fade-in pb-20 md:pb-0 flex-1 flex flex-col">
                <Flashcards 
                    data={allQuestions} 
                    onImageClick={setZoomedImage} 
                    mistakes={mistakesVault}
                    onToggleMistake={handleToggleMistake}
                    onClearMistakes={handleClearMistakes}
                />
              </div>
            )}

            {currentMode === AppMode.ATLAS && (
              <div className="w-full h-full animate-fade-in pb-20 md:pb-0 flex-1 flex flex-col">
                <InteractiveAtlas 
                    data={allQuestions} 
                    onImageClick={setZoomedImage} 
                    mistakes={mistakesVault}
                />
              </div>
            )}

            {currentMode === AppMode.QUIZ && (
              <div className="w-full h-full animate-scale-in pb-20 md:pb-0 flex-1 flex flex-col">
                <Quiz 
                  data={allQuestions} 
                  toggleHeader={setIsHeaderVisible} 
                  onImageClick={setZoomedImage}
                  mistakes={mistakesVault}
                  onAddMistake={(id) => handleToggleMistake(id, true)}
                  onRemoveMistake={(id) => handleToggleMistake(id, false)}
                />
              </div>
            )}

            {currentMode === AppMode.LIST && (
              <div className="w-full h-full overflow-y-auto px-0 md:px-4 py-0 md:py-6 custom-scrollbar pb-32 md:pb-6 animate-fade-in flex-1">
                <QuestionList 
                  data={allQuestions}
                  onImageClick={setZoomedImage}
                  mistakes={mistakesVault}
                  onToggleMistake={handleToggleMistake}
                  onClearMistakes={handleClearMistakes}
                />
                {userVault.length > 0 && (
                    <div className="flex justify-center p-8 md:p-12 pb-32">
                    <button onClick={() => confirm("Reset user data?") && setUserVault([])} className="text-[10px] font-black text-rose-300 uppercase tracking-widest hover:text-rose-500 transition-colors flex items-center gap-2">
                        <Trash2 size={12} /> Factory Reset User Data
                    </button>
                    </div>
                )}
              </div>
            )}
        </div>
      </main>

      <MobileNavigation 
        currentMode={currentMode} 
        onModeChange={(m) => setCurrentMode(m)}
        isVisible={isHeaderVisible}
      />

      <ImageZoomModal 
        isOpen={!!zoomedImage} 
        imageUrl={zoomedImage || ''} 
        onClose={() => setZoomedImage(null)} 
      />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Question } from '../types';
import { 
  ArrowLeft, ArrowRight, Volume2, 
  Shuffle, ImageIcon, Filter, Layers, 
  ArrowLeftRight, AlertTriangle, CheckCircle2, Trophy,
  RotateCcw, Search, Sparkles
} from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';
import FilterModal, { FilterOption } from './FilterModal';
import { cleanImageUrl } from '../utils';

interface FlashcardsProps {
  data: Question[];
  onImageClick?: (url: string) => void;
  mistakes?: string[]; 
  onToggleMistake?: (id: string, shouldAdd: boolean) => void; 
  onClearMistakes?: () => void;
}

const Flashcards: React.FC<FlashcardsProps> = ({ 
    data, 
    onImageClick, 
    mistakes = [], 
    onToggleMistake, 
    onClearMistakes 
}) => {
  const [currentIndex, setCurrentIndex] = useState(() => {
    const saved = localStorage.getItem('ot_flashcard_index');
    return saved ? parseInt(saved, 10) : 0;
  });

  const [isShuffled, setIsShuffled] = useState(() => {
    return localStorage.getItem('ot_flashcard_shuffle') === 'true';
  });

  const [isReversed, setIsReversed] = useState(() => {
    return localStorage.getItem('ot_flashcard_reversed') === 'true';
  });

  const [isFlipped, setIsFlipped] = useState(false);

  const [showImagesOnly, setShowImagesOnly] = useState(() => localStorage.getItem('ot_filter_images') === 'true');
  const [showMistakesOnly, setShowMistakesOnly] = useState(() => localStorage.getItem('ot_filter_mistakes') === 'true');
  const [selectedCategories, setSelectedCategories] = useState<string[]>(() => {
    try {
      return JSON.parse(localStorage.getItem('ot_filter_categories') || '[]');
    } catch { return []; }
  });

  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const { speak, cancel, isSpeaking, speakingId } = useSpeech();

  const [touchStart, setTouchStart] = useState<{ x: number; y: number } | null>(null);
  const [touchEnd, setTouchEnd] = useState<{ x: number; y: number } | null>(null);
  const minSwipeDistance = 50;

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category));
    return Array.from(cats).sort((a: string, b: string) => 
      a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' })
    );
  }, [data]);

  const activeData = useMemo(() => {
    let filtered = data;
    if (showMistakesOnly) filtered = filtered.filter(q => mistakes.includes(q.id));
    if (showImagesOnly) filtered = filtered.filter(q => q.questionImage || q.answerImage);
    if (selectedCategories.length > 0) filtered = filtered.filter(q => selectedCategories.includes(q.category));

    if (isShuffled) {
        return [...filtered].sort((a, b) => a.id.localeCompare(b.id)); // Consistent sort for now
    }
    return filtered;
  }, [data, showImagesOnly, selectedCategories, showMistakesOnly, mistakes, isShuffled]);

  useEffect(() => localStorage.setItem('ot_flashcard_index', currentIndex.toString()), [currentIndex]);
  useEffect(() => localStorage.setItem('ot_flashcard_shuffle', String(isShuffled)), [isShuffled]);
  useEffect(() => localStorage.setItem('ot_flashcard_reversed', String(isReversed)), [isReversed]);
  useEffect(() => localStorage.setItem('ot_filter_images', String(showImagesOnly)), [showImagesOnly]);
  useEffect(() => localStorage.setItem('ot_filter_mistakes', String(showMistakesOnly)), [showMistakesOnly]);
  useEffect(() => localStorage.setItem('ot_filter_categories', JSON.stringify(selectedCategories)), [selectedCategories]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (isFilterOpen) return;
      if (e.key === 'ArrowRight') {
        if (currentIndex < activeData.length - 1) {
          setIsFlipped(false);
          cancel();
          setTimeout(() => setCurrentIndex(c => c + 1), 150);
        }
      } else if (e.key === 'ArrowLeft') {
        if (currentIndex > 0) {
          setIsFlipped(false);
          cancel();
          setTimeout(() => setCurrentIndex(c => c - 1), 150);
        }
      } else if (e.key === ' ' || e.key === 'Enter') {
        e.preventDefault();
        setIsFlipped(prev => !prev);
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [currentIndex, activeData.length, isFilterOpen, cancel]); 

  const handleResolveMistake = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    onToggleMistake?.(id, false);
  };

  const handleWipeVault = () => {
    if (confirm("Permanently delete all recorded mistakes?")) {
        onClearMistakes?.();
        setShowMistakesOnly(false);
    }
  };

  useEffect(() => {
    if (activeData.length > 0 && currentIndex >= activeData.length) {
      setCurrentIndex(0);
    }
  }, [activeData.length]);

  const currentCard = activeData[currentIndex];

  const frontContent = isReversed ? {
    label: 'Answer', text: currentCard?.answerText, image: currentCard?.answerImage, isQuestion: false
  } : {
    label: 'Question', text: currentCard?.questionText, image: currentCard?.questionImage, isQuestion: true
  };

  const backContent = isReversed ? {
    label: 'Question', text: currentCard?.questionText, image: currentCard?.questionImage, isQuestion: true
  } : {
    label: 'Answer', text: currentCard?.answerText, image: currentCard?.answerImage, isQuestion: false
  };

  const handleNext = (e?: React.MouseEvent) => {
    e?.stopPropagation();
    if (currentIndex < activeData.length - 1) {
      setIsFlipped(false);
      cancel();
      setTimeout(() => setCurrentIndex(c => c + 1), 150);
    }
  };

  const handlePrev = (e?: React.MouseEvent) => {
    e?.stopPropagation();
    if (currentIndex > 0) {
      setIsFlipped(false);
      cancel();
      setTimeout(() => setCurrentIndex(c => c - 1), 150);
    }
  };

  const onTouchStart = (e: React.TouchEvent) => {
    setTouchEnd(null);
    setTouchStart({ x: e.targetTouches[0].clientX, y: e.targetTouches[0].clientY });
  };

  const onTouchMove = (e: React.TouchEvent) => {
    setTouchEnd({ x: e.targetTouches[0].clientX, y: e.targetTouches[0].clientY });
  };

  const onTouchEnd = () => {
    if (!touchStart || !touchEnd) return;
    const distanceX = touchStart.x - touchEnd.x;
    const distanceY = touchStart.y - touchEnd.y;
    if (Math.abs(distanceX) > Math.abs(distanceY)) {
      if (distanceX > minSwipeDistance) handleNext();
      else if (distanceX < -minSwipeDistance) handlePrev();
    }
  };

  const handleSpeak = (e: React.MouseEvent, text: string, suffix: string) => {
    e.stopPropagation();
    if (isSpeaking) cancel(); else speak(text, currentCard.id + suffix);
  };

  const getTextSizeClass = (text: string = '') => {
    const len = text.length;
    if (len < 20) return 'text-3xl md:text-5xl';
    if (len < 60) return 'text-2xl md:text-4xl';
    if (len < 120) return 'text-xl md:text-3xl';
    if (len < 250) return 'text-lg md:text-2xl';
    if (len < 400) return 'text-base md:text-xl';
    return 'text-sm md:text-lg'; 
  };

  const formatCardText = (text: string = '') => {
    if (!text) return '';
    return text
      .replace(/^Define the term:\s*/i, '')
      .replace(/^Anatomical term for:\s*/i, '')
      .replace(/^Define:\s*/i, '')
      .replace(/^Identify the\s+/i, '')
      .trim();
  };

  const filterOptions: FilterOption[] = [
    {
        label: 'Diagrams Only',
        subLabel: 'Visual Study',
        icon: ImageIcon,
        isActive: showImagesOnly,
        onClick: () => { setShowImagesOnly(!showImagesOnly); setShowMistakesOnly(false); },
        colorTheme: 'indigo'
    }
  ];

  if (!currentCard) {
    return (
      <div className="flex flex-col items-center justify-center h-full p-8 text-center space-y-8 animate-in fade-in zoom-in-95 duration-500">
        <div className={`w-24 h-24 rounded-full flex items-center justify-center shadow-lg border-4 ${showMistakesOnly ? 'bg-rose-50 text-rose-600 border-rose-100' : 'bg-white text-slate-400 border-slate-100'}`}>
           {showMistakesOnly ? <Trophy size={48} /> : <Layers size={48} />}
        </div>
        <div className="space-y-3 max-w-xs mx-auto">
            <h3 className="text-2xl font-bold text-slate-900 tracking-tight font-display">
                {showMistakesOnly ? "Review Complete" : "No Cards Found"}
            </h3>
            <p className="text-slate-500 font-medium leading-relaxed">
                {showMistakesOnly ? "Excellent work! You've resolved all items in your Smart Review list." : "Try adjusting your filters to see more cards."}
            </p>
        </div>
        <button 
          onClick={() => { setSelectedCategories([]); setShowImagesOnly(false); setShowMistakesOnly(false); }}
          className="px-8 py-3 bg-slate-900 text-white rounded-xl font-bold uppercase tracking-widest text-xs hover:bg-slate-800 transition-all shadow-lg active:scale-95"
        >
          Reset Filters
        </button>
      </div>
    );
  }

  const frontDisplayText = formatCardText(frontContent.text);
  const backDisplayText = formatCardText(backContent.text);

  return (
    <div className="flex flex-col h-full max-w-5xl mx-auto w-full relative">
      {/* Top Controls */}
      <div className="flex justify-between items-center px-4 md:px-6 py-2 md:py-6 shrink-0 gap-3 overflow-x-auto no-scrollbar">
        <div className="flex items-center gap-2">
           <button 
             onClick={() => setIsFilterOpen(true)}
             className={`w-10 h-10 md:w-12 md:h-12 rounded-2xl border transition-all flex items-center justify-center shrink-0 ${selectedCategories.length > 0 || showImagesOnly ? 'border-rose-200 bg-rose-50 text-rose-700' : 'bg-white border-slate-200 text-slate-400 hover:border-slate-300'}`}
           >
             <Filter className="w-4 h-4 md:w-[18px] md:h-[18px]" strokeWidth={2} />
           </button>

           {mistakes.length > 0 && (
                <button 
                    onClick={() => { setShowMistakesOnly(!showMistakesOnly); if(!showMistakesOnly) setCurrentIndex(0); }}
                    className={`flex items-center gap-2 px-3 py-1 md:py-2 md:px-4 rounded-xl border transition-all shrink-0 ${showMistakesOnly ? 'bg-rose-100 border-rose-300 text-rose-800 shadow-sm' : 'bg-white border-slate-200 text-slate-500 hover:border-rose-200 hover:text-rose-600'}`}
                >
                    <AlertTriangle size={16} className={showMistakesOnly ? "fill-rose-500 text-rose-600" : ""} />
                    <div className="flex flex-col items-start text-[10px] uppercase font-black tracking-wider leading-none">
                        <span>Smart Review</span>
                        <span className="opacity-60 text-[9px] mt-0.5">{mistakes.length} Items</span>
                    </div>
                </button>
           )}
        </div>

        <div className="flex items-center gap-2">
           <span className="text-base md:text-lg font-black text-slate-900 font-display flex items-baseline gap-1 mr-2 hidden sm:flex">
                 {currentIndex + 1} 
                 <span className="text-xs md:text-sm font-bold text-slate-300">/ {activeData.length}</span>
           </span>

           <button 
             onClick={() => { setIsReversed(!isReversed); setIsFlipped(false); }}
             className={`w-10 h-10 md:w-12 md:h-12 rounded-2xl border transition-all flex items-center justify-center hover:bg-slate-50 shrink-0 ${isReversed ? 'border-emerald-500 text-emerald-600 bg-emerald-50' : 'bg-white border-slate-200 text-slate-400'}`}
             title="Reverse Sides"
           >
             <ArrowLeftRight className="w-4 h-4 md:w-[18px] md:h-[18px]" strokeWidth={2} />
           </button>
           <button 
             onClick={() => { setIsShuffled(!isShuffled); setCurrentIndex(0); }}
             className={`w-10 h-10 md:w-12 md:h-12 rounded-2xl border transition-all flex items-center justify-center hover:bg-slate-50 shrink-0 ${isShuffled ? 'border-purple-500 text-purple-600 bg-purple-50' : 'bg-white border-slate-200 text-slate-400'}`}
             title="Shuffle Deck"
           >
             <Shuffle className="w-4 h-4 md:w-[18px] md:h-[18px]" strokeWidth={2} />
           </button>
        </div>
      </div>

      {/* Card Container */}
      <div className="flex-1 px-4 md:px-8 pb-2 flex flex-col justify-center min-h-0 relative perspective-1000">
        <div 
          className="relative w-full h-full cursor-pointer select-none"
          onClick={() => setIsFlipped(!isFlipped)}
          onTouchStart={onTouchStart}
          onTouchMove={onTouchMove}
          onTouchEnd={onTouchEnd}
        >
          <div className={`relative w-full h-full transition-all duration-500 transform-style-3d ${isFlipped ? 'rotate-y-180' : ''}`}>

            {/* FRONT FACE */}
            <div className="absolute inset-0 backface-hidden bg-white rounded-[2rem] md:rounded-[2.5rem] shadow-card hover:shadow-card-hover border border-slate-100 p-5 md:p-12 flex flex-col group overflow-hidden">
               <div className="w-full flex justify-between items-start mb-2 shrink-0">
